mapper.select:
SELECT shop.id, shop.`name`, pc.id as category_id, pc.`name` as category_name FROM shop LEFT JOIN product_category pc ON shop.id = pc.shop_id WHERE shop.id IN ( SELECT DISTINCT shop.id FROM shop LEFT JOIN product_category ON shop.id = product_category.shop_id
product_category.name like CONCAT('%', #{name}, '%')
)

SELECT s.id AS shop_id, s.name AS shop_name, s.address, s.phone, s.logo, s.business_hours, s.status, s.create_time, s.update_time, s.business_scope, s.parking_info, s.introduction, p.id AS product_id, p.name AS product_name, p.price, p.sales, p.image, p.rank FROM shop s LEFT JOIN ( SELECT p1.id, p1.shop_id, p1.name, p1.price, p1.sales, p1.image, (SELECT COUNT(*) FROM product p2 WHERE p2.shop_id = p1.shop_id AND p2.sales > p1.sales) + 1 AS rank FROM product p1 WHERE p1.sales IS NOT NULL AND p1.sales > 0 ) p ON s.id = p.shop_id AND p.rank <= 5
${ew.sqlSegment}
ORDER BY s.id, p.rank

SELECT s.id AS shop_id, s.name AS shop_name, s.address, s.phone, s.logo, s.business_hours, s.status, s.create_time, s.update_time, s.business_scope, s.parking_info, s.introduction, IFNULL(o.order_cnt, 0) AS order_cnt, p.id AS product_id, p.name AS product_name, p.price, p.sales, p.image, p.rank FROM shop s LEFT JOIN ( SELECT shop_id, COUNT(*) AS order_cnt FROM `order` GROUP BY shop_id ) o ON s.id = o.shop_id LEFT JOIN ( SELECT p1.id, p1.shop_id, p1.name, p1.price, p1.sales, p1.image, (SELECT COUNT(*) FROM product p2 WHERE p2.shop_id = p1.shop_id AND p2.sales > p1.sales) + 1 AS rank FROM product p1 WHERE p1.sales IS NOT NULL AND p1.sales > 0 ) p ON s.id = p.shop_id AND p.rank <= 5 WHERE s.id IN
#{shopId}
ORDER BY s.id, p.rank
